+// ── Export for Section 13 success criteria ────────────────────────────────────
+
+/// Ecosystem health export for program success measurement.
+#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
+pub struct EcosystemHealthExport {
+    /// Export timestamp.
