+// ── Resource budget ──────────────────────────────────────────────────────────
+
+/// Resource budget limits for the telemetry pipeline.
+#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
+pub struct ResourceBudget {
+    /// Maximum data points stored in memory.
+    pub max_in_memory_points: usize,
